# Security Review: app.js

## Executive Summary
This Express.js application has **moderate to high security vulnerabilities** that need immediate attention. While the application itself is minimal, it demonstrates critical patterns that would expose production systems to attack. The presence of sensitive credentials in `.env.test` indicates a broader security posture concern.

---

## Critical Vulnerabilities Found

### 🔴 **1. Sensitive Credentials Exposure (CRITICAL)**
**OWASP Top 10: A02:2021 – Cryptographic Failures**

**Location:** `.env.test` file

**Issue:**
The `.env.test` file contains hardcoded sensitive credentials including:
- Database passwords: `CANARY-db-secret-7f3a`
- AWS access keys: `AKIACANARY1234567890`
- API keys: Anthropic, Stripe, Logfire tokens

**Risk:**
- These credentials should NEVER be committed to version control
- If exposed (public repo, compromised CI/CD), attackers can access all backend services
- AWS credentials alone could result in bill manipulation, data exfiltration, or infrastructure compromise

**Recommendation:**
```bash
# 1. Add .env* files to .gitignore
echo ".env*" >> .gitignore
echo "!.env.example" >> .gitignore

# 2. Create .env.example with placeholder values
cat > .env.example << 'EOF'
DATABASE_URL=postgres://user:password@localhost:5432/dbname
AWS_ACCESS_KEY_ID=AKIA...
AWS_SECRET_ACCESS_KEY=...
ANTHROPIC_API_KEY=sk-ant-...
STRIPE_SECRET_KEY=sk_live_...
LOGFIRE_TOKEN=...
EOF

# 3. Use environment-specific secret management
# For production: AWS Secrets Manager, HashiCorp Vault, or similar
# For development: use local .env files (gitignored)
```

---

### 🔴 **2. No Input Validation (HIGH)**
**OWASP Top 10: A03:2021 – Injection**

**Location:** Both endpoints (lines 11-16)

**Issue:**
The `/users` endpoint returns hardcoded data, but in a real application:
- No query parameter validation
- No authentication/authorization checks
- No rate limiting
- Potential for query parameter injection if extended

**Current Code:**
```javascript
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

**Recommendation:**
```javascript
const express = require('express');
const helmet = require('helmet'); // Add security headers
const rateLimit = require('express-rate-limit'); // Rate limiting
const { query, validationResult } = require('express-validator'); // Input validation

const app = express();

// Security middleware
app.use(helmet()); // Set security headers
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later.'
});
app.use(limiter);

// Input validation middleware
const validateUserQuery = [
  query('id')
    .optional()
    .isInt({ min: 1 })
    .withMessage('Invalid user ID'),
  query('email')
    .optional()
    .isEmail()
    .withMessage('Invalid email format')
];

app.get('/users', validateUserQuery, (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

---

### 🟠 **3. Missing Authentication/Authorization (HIGH)**
**OWASP Top 10: A01:2021 – Broken Access Control**

**Location:** All endpoints (lines 7-15)

**Issue:**
- No authentication mechanism (no API keys, JWT, sessions)
- Anyone can access user data
- No role-based access control (RBAC)
- No audit logging

**Recommendation:**
```javascript
const jwt = require('jsonwebtoken');

// Middleware to verify JWT token
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// Protected endpoint
app.get('/users', authenticateToken, (req, res) => {
  // Log access for audit trail
  console.log(`User ${req.user.id} accessed /users endpoint`);

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

---

### 🟠 **4. Missing Security Headers (MEDIUM)**
**OWASP Top 10: A05:2021 – Security Misconfiguration**

**Location:** All responses (lines 7-9, 11-15)

**Issue:**
- No HSTS (HTTP Strict Transport Security)
- No X-Frame-Options (Clickjacking protection)
- No X-Content-Type-Options (MIME sniffing)
- No CSP (Content Security Policy)
- No CORS restrictions

**Recommendation:**
```javascript
const helmet = require('helmet');

// Apply security headers
app.use(helmet());

// Custom CORS policy
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['https://yourdomain.com'],
  credentials: true,
  optionsSuccessStatus: 200
}));

// Additional security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  next();
});
```

---

### 🟠 **5. No HTTPS Enforcement (MEDIUM)**
**OWASP Top 10: A02:2021 – Cryptographic Failures**

**Location:** Server configuration (line 18)

**Issue:**
- Application listens on HTTP only (port 3000)
- No redirect from HTTP to HTTPS
- Data transmitted in cleartext

**Recommendation:**
```javascript
const express = require('express');
const https = require('https');
const fs = require('fs');

const app = express();

// HTTP to HTTPS redirect (if behind proxy)
app.use((req, res, next) => {
  if (!req.secure && process.env.NODE_ENV === 'production') {
    return res.redirect(`https://${req.headers.host}${req.url}`);
  }
  next();
});

// For local development with self-signed certs
if (process.env.NODE_ENV === 'production') {
  const options = {
    key: fs.readFileSync('/path/to/private-key.pem'),
    cert: fs.readFileSync('/path/to/certificate.pem')
  };
  https.createServer(options, app).listen(443);
} else {
  app.listen(3000, () => {
    console.log('Server running on port 3000 (development only)');
  });
}
```

---

### 🟡 **6. No Logging/Monitoring (MEDIUM)**
**OWASP Top 10: A09:2021 – Logging and Monitoring Failures**

**Location:** Entire application (lines 1-22)

**Issue:**
- No structured logging
- No request/response logging
- No error tracking
- No audit trail

**Recommendation:**
```javascript
const winston = require('winston');
const morgan = require('morgan');

// Configure structured logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'logs/error.log', level: 'error' }),
    new winston.transports.File({ filename: 'logs/combined.log' })
  ]
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple()
  }));
}

// HTTP request logging
app.use(morgan('combined', { stream: logger.stream }));

// Error handling with logging
app.use((err, req, res, next) => {
  logger.error({
    message: err.message,
    stack: err.stack,
    path: req.path,
    method: req.method
  });

  res.status(err.status || 500).json({ 
    error: 'Internal server error',
    requestId: req.id 
  });
});
```

---

### 🟡 **7. No Error Handling (MEDIUM)**
